TFuture<TArray<FString>> UTbSimpleSimpleArrayInterfaceMQTTClient::FuncStringAsync(const TArray<FString>& ParamString)
{
	TRACE_CPUPROFILER_EVENT_SCOPE_STR("ApiGear.TbSimple.SimpleArrayInterface.MQTT.FuncStringAsync");
	if (!Connection.GetObject())
	{
		UE_LOG(LogTbSimpleSimpleArrayInterfaceMQTTClient, Error, TEXT("No connection for %s. Are the ApiGear TbSimple plugin settings correct? Is the service set up correctly?"), TEXT("TbSimpleSimpleArrayInterface"));

		TPromise<TArray<FString>> Promise;
		Promise.SetValue(TArray<FString>());
		return Promise.GetFuture();
	}

	TSharedRef<TPromise<TArray<FString>>> Promise = MakeShared<TPromise<TArray<FString>>>();

	ApiGear::MQTT::InvokeReplyFunc ResponseFunc = [Promise](const ApiGear::MQTT::InvokeReplyArg& args)
	{
		if (args.JsonValue.empty())
		{
			UE_LOG(LogTbSimpleSimpleArrayInterfaceMQTTClient, Error, TEXT("FuncStringAsync: MQTT service returned empty value - should have returned type of TArray<FString>"));
			Promise->SetValue(TArray<FString>());
			return;
		}

		nlohmann::json json_result = nlohmann::json::parse(args.JsonValue);
		Promise->SetValue(json_result.get<TArray<FString>>());
	};

	FGuid CorrelationId = RegisterResponseHandler(MoveTemp(ResponseFunc));

	UApiGearMQTTClient* ApiGearMQTTClient = Cast<UApiGearMQTTClient>(Connection.GetObject());
	static const FString Topic = FString(TEXT("tb.simple/SimpleArrayInterface/rpc/funcString"));

	const FString CorrelationStr = CorrelationId.ToString();
	TArray<uint8> CorrelationBytes;
	{
		FTCHARToUTF8 GuidUtf8(*CorrelationStr);
		CorrelationBytes.Append(reinterpret_cast<const uint8*>(GuidUtf8.Get()), GuidUtf8.Length());
	}
	const FString ResponseTopic = FString::Printf(
		TEXT("tb.simple/SimpleArrayInterface/rpc/funcString/%s/result"),
		*ApiGearMQTTClient->getClientId());

	const nlohmann::json ArgsJson = nlohmann::json::array({ParamString});

	ApiGearMQTTClient->invokeRemoteWithProps(Topic,
		UTF8_TO_TCHAR(ArgsJson.dump().c_str()),
		ResponseTopic, CorrelationBytes);

	return Promise->GetFuture();
}

void UTbSimpleSimpleArrayInterfaceMQTTClient::onSigBool(const IApiGearMqttClient::FReceivedMessage& InMsg)
{
	const std::string Payload(reinterpret_cast<const char*>(InMsg.Payload.GetData()), InMsg.Payload.Num());
	nlohmann::json json_args = nlohmann::json::parse(Payload);

	// check for correct array size
	if (!json_args.is_array() || json_args.size() < 1)
	{
		UE_LOG(LogTbSimpleSimpleArrayInterfaceMQTTClient, Error, TEXT("Signal sigBool: invalid args array (expected 1 elements)"));
		return;
	}

	// make sure the type matches our expectation
	if (json_args[0].is_null() || !json_args[0].is_array())
	{
		UE_LOG(LogTbSimpleSimpleArrayInterfaceMQTTClient, Error, TEXT("Signal paramBool: invalid type for parameter 0"));
		return;
	}
	const TArray<bool>& outParamBool = json_args[0].get<TArray<bool>>();

	TWeakObjectPtr<UTbSimpleSimpleArrayInterfaceMQTTClient> weak(this);
	AsyncTask(ENamedThreads::GameThread, [weak, outParamBool]()
		{
		if (auto* self = weak.Get())
		{
			self->_GetPublisher()->BroadcastSigBoolSignal(outParamBool);
		}
	});
}

